        } else {
            window.showWarningNotification('אין לוג להעתקה');
        }
    } catch (err) {
        window.Logger.error('שגיאה בהעתקה:', err, { page: "index" });
        window.showErrorNotification('שגיאה בהעתקת הלוג');
