        };

        // Capture console messages
        const originalError = console.error;
        const originalWarn = console.warn;
        const originalLog = console.log;

        console.error = function(...args) {
            logData.console.errors.push(args.join(' '));
            originalError.apply(console, args);
        };

        console.warn = function(...args) {
            logData.console.warnings.push(args.join(' '));
            originalWarn.apply(console, args);
        };

        console.log = function(...args) {
            logData.console.logs.push(args.join(' '));
            originalLog.apply(console, args);
        };

        return JSON.stringify(logData, null, 2);
    } catch (error) {
        return `Error generating log: ${error.message}`;
    }
}

loadExecutionTickerInfo(tickerId) {
  try {
    window.Logger.info('🔄 Loading ticker info for ID:', tickerId, { page: "executions" });

    // Get ticker data from API
    const response = await fetch(`/api/tickers/`);
    if (!response.ok) {
      throw new Error(`HTTP error! status: ${response.status}`);
    }

    const data = await response.json();
    const tickers = data.data || data;

    // Find the specific ticker
    const ticker = tickers.find(t => t.id == tickerId);
    if (!ticker) {
      throw new Error('Ticker not found');
    }

    // Display ticker info
    await displayExecutionTickerInfo(ticker);

    // Set default quantity to 100
    if (typeof window.DataCollectionService !== 'undefined' && window.DataCollectionService.setValue) {
      window.DataCollectionService.setValue('executionQuantity', 100, 'int');
    } else {
      const quantityField = document.getElementById('executionQuantity');
      if (quantityField) {
        quantityField.value = 100;
      }
    }

    // Set default price to current price
    if (ticker.current_price) {
      if (typeof window.DataCollectionService !== 'undefined' && window.DataCollectionService.setValue) {
        window.DataCollectionService.setValue('executionPrice', ticker.current_price, 'number');
      } else {
        const priceField = document.getElementById('executionPrice');
        if (priceField) {
          priceField.value = ticker.current_price;
        }
      }
    }

    // Set default commission from preferences
    try {
      if (typeof window.getPreference === 'function') {
        const defaultCommission = await window.getPreference('defaultCommission');
        if (defaultCommission !== null && defaultCommission !== undefined) {
          if (typeof window.DataCollectionService !== 'undefined' && window.DataCollectionService.setValue) {
            window.DataCollectionService.setValue('executionCommission', defaultCommission, 'number');
          } else {
            const commissionField = document.getElementById('executionCommission');
            if (commissionField) {
              commissionField.value = defaultCommission;
            }
          }
        }
      }
    } catch (error) {
      // Default commission preference may not be available - this is not critical
      // Log at debug level to avoid console noise during tests
      window.Logger.debug('Default commission preference not available (optional)', {
        page: "executions",
        error: error?.message,
        note: 'This is expected if preference is not set'
      });
    }

  } catch (error) {
    window.Logger.error('❌ Error loading ticker info:', error, { page: "executions" });
  }
}

