updateEditTickerInfo() {
  // Use DataCollectionService to get values if available
  let tickerId, tradePlanId;
  if (typeof window.DataCollectionService !== 'undefined' && window.DataCollectionService.getValue) {
    tickerId = window.DataCollectionService.getValue('editTradePlanTickerId', 'int', 0);
    tradePlanId = window.DataCollectionService.getValue('editTradePlanId', 'int', 0);
  } else {
    const tickerIdEl = document.getElementById('editTradePlanTickerId');
    const tradePlanIdEl = document.getElementById('editTradePlanId');
    tickerId = tickerIdEl ? tickerIdEl.value : 0;
    tradePlanId = tradePlanIdEl ? tradePlanIdEl.value : 0;
  }
  const tickerDisplay = document.getElementById('editSelectedTickerDisplay');
  const priceDisplay = document.getElementById('editCurrentPriceDisplay');
  const changeDisplay = document.getElementById('editDailyChangeDisplay');

  if (!tickerId) {
    tickerDisplay.textContent = 'לא נבחר';
    priceDisplay.textContent = '-';
    changeDisplay.textContent = '-';
    return;
  }

  // בדיקה אם הטיקר השתנה (רק אם יש תכנון נבחר)
  if (tradePlanId) {
    const originalTradePlan = window.tradePlansData.find(tp => tp.id === tradePlanId);
    if (originalTradePlan && originalTradePlan.ticker_id !== tickerId) {
      // Ticker changed from original to new

      // הצגת הודעת אישור לשינוי טיקר
      if (typeof window.showConfirmationDialog === 'function') {
        window.showConfirmationDialog(
          'שינוי טיקר לתכנון',
          'האם אתה בטוח שברצונך לשנות את הטיקר של התכנון?\n\nפעולה זו תשנה את הטיקר המקורי של התכנון.',
          () => {
            // המשתמש אישר - הצגת הודעה שהפיצ'ר לא נתמך
            if (typeof window.showWarningNotification === 'function') {
              window.showWarningNotification(
                'פיצ\'ר לא נתמך',
                'שינוי טיקר לתכנון לא נתמך עדיין. הטיקר יוחזר למצבו המקורי.',
              );
            }
            // החזרת הטיקר למצבו המקורי
            // Use DataCollectionService to set value if available
            if (typeof window.DataCollectionService !== 'undefined' && window.DataCollectionService.setValue) {
              window.DataCollectionService.setValue('editTradePlanTickerId', originalTradePlan.ticker_id, 'int');
            } else {
              const tickerIdEl = document.getElementById('editTradePlanTickerId');
              if (tickerIdEl) tickerIdEl.value = originalTradePlan.ticker_id;
            }
            // עדכון התצוגה עם הטיקר המקורי
            updateEditTickerInfo();
            return;
          },
          () => {
            // המשתמש ביטל - מחזירים את הטיקר המקורי
            // Use DataCollectionService to set value if available
            if (typeof window.DataCollectionService !== 'undefined' && window.DataCollectionService.setValue) {
              window.DataCollectionService.setValue('editTradePlanTickerId', originalTradePlan.ticker_id, 'int');
            } else {
              const tickerIdEl = document.getElementById('editTradePlanTickerId');
              if (tickerIdEl) tickerIdEl.value = originalTradePlan.ticker_id;
            }
            // עדכון התצוגה עם הטיקר המקורי
            updateEditTickerInfo();
            return;
          },
        );
      } else {
        // Fallback למקרה שהפונקציה לא זמינה
        if (typeof window.showConfirmationDialog === 'function') {
          window.showConfirmationDialog(
            'שינוי טיקר לתכנון',
            'האם אתה בטוח שברצונך לשנות את הטיקר של התכנון?',
            () => {
              if (typeof window.showWarningNotification === 'function') {
                window.showWarningNotification(
                  'פיצ\'ר לא נתמך',
                  'שינוי טיקר לתכנון לא נתמך עדיין. הטיקר יוחזר למצבו המקורי.',
                );
              }
              // Use DataCollectionService to set value if available
            if (typeof window.DataCollectionService !== 'undefined' && window.DataCollectionService.setValue) {
              window.DataCollectionService.setValue('editTradePlanTickerId', originalTradePlan.ticker_id, 'int');
            } else {
              const tickerIdEl = document.getElementById('editTradePlanTickerId');
              if (tickerIdEl) tickerIdEl.value = originalTradePlan.ticker_id;
            }
              updateEditTickerInfo();
            },
            () => {
              // Use DataCollectionService to set value if available
            if (typeof window.DataCollectionService !== 'undefined' && window.DataCollectionService.setValue) {
              window.DataCollectionService.setValue('editTradePlanTickerId', originalTradePlan.ticker_id, 'int');
            } else {
              const tickerIdEl = document.getElementById('editTradePlanTickerId');
              if (tickerIdEl) tickerIdEl.value = originalTradePlan.ticker_id;
            }
              updateEditTickerInfo();
            },
          );
        } else {
            // Fallback למקרה שמערכת התראות לא זמינה
            let confirmed = false;
            if (typeof showConfirmationDialog === 'function') {
              confirmed = await new Promise(resolve => {
                showConfirmationDialog(
                  'האם אתה בטוח שברצונך לשנות את הטיקר של התכנון?',
                  () => resolve(true),
                  () => resolve(false),
                  'שינוי טיקר',
                  'שנה',
                  'ביטול'
                );
              });
            } else if (typeof window.showConfirmationDialog === 'function') {
              confirmed = await new Promise(resolve => {
                window.showConfirmationDialog(
                  'שינוי טיקר',
                  'האם אתה בטוח שברצונך לשנות את הטיקר של התכנון?',
                  () => resolve(true),
                  () => resolve(false),
                  'warning'
                );
              });
            } else {
              confirmed = window.confirm('האם אתה בטוח שברצונך לשנות את הטיקר של התכנון?');
            }
            if (confirmed) {
              if (typeof window.showWarningNotification === 'function') {
                window.showWarningNotification(
                  'פיצ\'ר לא נתמך',
                  'שינוי טיקר לתכנון לא נתמך עדיין. הטיקר יוחזר למצבו המקורי.',
                );
              }
              // Use DataCollectionService to set value if available
            if (typeof window.DataCollectionService !== 'undefined' && window.DataCollectionService.setValue) {
              window.DataCollectionService.setValue('editTradePlanTickerId', originalTradePlan.ticker_id, 'int');
            } else {
              const tickerIdEl = document.getElementById('editTradePlanTickerId');
              if (tickerIdEl) tickerIdEl.value = originalTradePlan.ticker_id;
            }
              updateEditTickerInfo();
            } else {
              // Use DataCollectionService to set value if available
            if (typeof window.DataCollectionService !== 'undefined' && window.DataCollectionService.setValue) {
              window.DataCollectionService.setValue('editTradePlanTickerId', originalTradePlan.ticker_id, 'int');
            } else {
              const tickerIdEl = document.getElementById('editTradePlanTickerId');
              if (tickerIdEl) tickerIdEl.value = originalTradePlan.ticker_id;
            }
              updateEditTickerInfo();
            }
          }
        }
      }
    }

  // מציאת הטיקר בנתונים
  let ticker = null;
  if (typeof window.tickerService?.getTickers === 'function') {
    try {
      const tickers = await window.tickerService.getTickers();
      ticker = tickers.find(t => t.id === tickerId);
    } catch {
      // window.Logger.warn('Error getting tickers from service:', error, { page: "trade_plans" });
    }
  }

  if (!ticker && window.tickersData) {
    ticker = window.tickersData.find(t => t.id === tickerId);
  }

  if (ticker) {
    tickerDisplay.textContent = ticker.symbol;

    // טיפול במחיר
    const parsedPrice = Number(ticker.current_price);
    const hasValidPrice = Number.isFinite(parsedPrice) && parsedPrice > 0;

    if (hasValidPrice) {
      priceDisplay.textContent = `$${parsedPrice.toFixed(2)}`;
    } else {
      priceDisplay.textContent = '-';
      if (typeof window.showErrorNotification === 'function') {
        window.showErrorNotification(
          'מחיר לא זמין',
          `לא התקבל מחיר עדכני לטיקר ${ticker.symbol}. אנא בדוק את מקורות הנתונים או טען מחדש את העמוד.`,
          6000,
          'system'
        );
      }
      window.Logger?.warn('⚠️ Missing current_price for ticker', { symbol: ticker.symbol, tickerId, page: 'trade_plans' });
    }

    const changeRaw = Number(ticker.daily_change);
    const changePercentRaw = Number(ticker.daily_change_percent);
    const hasValidChange = Number.isFinite(changeRaw) && Number.isFinite(changePercentRaw);

    if (hasValidChange) {
      const changeClass = changeRaw >= 0 ? 'positive' : 'negative';
      const changeSign = changeRaw >= 0 ? '+' : '';
      changeDisplay.textContent = `${changeSign}${changeRaw.toFixed(2)} (${changePercentRaw >= 0 ? '+' : ''}${changePercentRaw.toFixed(2)}%)`;
      changeDisplay.className = `form-control-plaintext ${changeClass}`;
    } else {
      changeDisplay.textContent = '-';
      changeDisplay.className = 'form-control-plaintext neutral';
      window.Logger?.warn('⚠️ Missing change data for ticker', { symbol: ticker.symbol, tickerId, page: 'trade_plans' });
    }

    // Add change from open display if available
    const changeFromOpenRaw = Number(ticker.change_from_open);
    const changeFromOpenPercentRaw = Number(ticker.change_from_open_percent);
    const hasValidChangeFromOpen = Number.isFinite(changeFromOpenRaw) && Number.isFinite(changeFromOpenPercentRaw);

    if (hasValidChangeFromOpen) {
      // Try to find or create change from open display element
      let changeFromOpenDisplay = document.getElementById('editTradePlanChangeFromOpen');
      if (!changeFromOpenDisplay) {
        // Create element if it doesn't exist
        const changeFromOpenRow = document.createElement('div');
        changeFromOpenRow.className = 'mb-3';
        const label = document.createElement('label');
        label.className = 'form-label';
        label.textContent = 'שינוי מפתיחה';
        changeFromOpenRow.appendChild(label);
        const changeDiv = document.createElement('div');
        changeDiv.id = 'editTradePlanChangeFromOpen';
        changeDiv.className = 'form-control-plaintext';
        changeFromOpenRow.appendChild(changeDiv);
        // Insert after change display
        if (changeDisplay && changeDisplay.parentElement) {
          changeDisplay.parentElement.parentElement.insertAdjacentElement('afterend', changeFromOpenRow);
        }
        changeFromOpenDisplay = document.getElementById('editTradePlanChangeFromOpen');
      }

      if (changeFromOpenDisplay) {
        const changeFromOpenClass = changeFromOpenRaw >= 0 ? 'positive' : 'negative';
        const changeFromOpenSign = changeFromOpenRaw >= 0 ? '+' : '';
        changeFromOpenDisplay.textContent = `${changeFromOpenSign}${changeFromOpenRaw.toFixed(2)} (${changeFromOpenPercentRaw >= 0 ? '+' : ''}${changeFromOpenPercentRaw.toFixed(2)}%)`;
        changeFromOpenDisplay.className = `form-control-plaintext ${changeFromOpenClass}`;
      }
    }
  } else {
    tickerDisplay.textContent = 'לא נמצא';
    priceDisplay.textContent = '-';
    changeDisplay.textContent = '-';
  }
}

generateDetailedLog() {
    const timestamp = window.formatDate ? window.formatDate(new Date(), true) : (window.dateUtils?.formatDate ? window.dateUtils.formatDate(new Date(), { includeTime: true }) : new Date().toLocaleString('he-IL'));
    const log = [];

    log.push('=== לוג מפורט - תזרימי מזומנים ===');
    log.push(`זמן יצירה: ${timestamp}`);
    log.push(`עמוד: ${window.location.href}`);
    log.push('');

    // 1. מצב כללי של העמוד
    log.push('--- מצב כללי של העמוד ---');
    const sections = document.querySelectorAll('.content-section, .section');
    sections.forEach((section, index) => {
        const header = section.querySelector('.section-header, h2, h3');
        const body = section.querySelector('.section-body, .card-body');
        const isOpen = body && body.style.display !== 'none' && !section.classList.contains('collapsed');
        const title = header ? header.textContent.trim() : `סקשן ${index + 1}`;
        log.push(`  ${index + 1}. "${title}": ${isOpen ? 'פתוח' : 'סגור'}`);
    });

    // 2. סטטיסטיקות תזרימי מזומנים
    log.push('');
    log.push('--- סטטיסטיקות תזרימי מזומנים ---');
    const cashFlowStats = [
        'totalCashFlows', 'totalDeposits', 'totalWithdrawals', 
        'newAlerts', 'currentBalance'
    ];

    cashFlowStats.forEach(statId => {
        const element = document.getElementById(statId);
        if (element) {
            const value = element.textContent.trim();
            const visible = element.offsetParent !== null ? 'נראה' : 'לא נראה';
            log.push(`${statId}: ${value} (${visible})`);
        }
    });

    // 3. טבלת תזרימי מזומנים
    log.push('');
    log.push('--- טבלת תזרימי מזומנים ---');
    const table = document.querySelector('#cashFlowsTable, .table, table');
    if (table) {
        const rows = table.querySelectorAll('tbody tr');
        log.push(`מספר שורות: ${rows.length}`);
        rows.forEach((row, index) => {
            const cells = row.querySelectorAll('td');
            const rowData = Array.from(cells).map(cell => cell.textContent.trim()).join(' | ');
            log.push(`  ${index + 1}. ${rowData}`);
        });
    } else {
        log.push('טבלה לא נמצאה');
    }

    // 4. כפתורים וקונטרולים
    log.push('');
    log.push('--- כפתורים וקונטרולים ---');
    const buttonIds = [
        'addCashFlowBtn', 'editCashFlowBtn', 'deleteCashFlowBtn', 'filterBtn',
        'exportBtn', 'refreshBtn', 'searchBtn'
    ];

    buttonIds.forEach(btnId => {
        const btn = document.getElementById(btnId);
        if (btn) {
            const visible = btn.offsetParent !== null ? 'נראה' : 'לא נראה';
            const disabled = btn.disabled ? 'מבוטל' : 'פעיל';
            const text = btn.textContent.trim() || btn.value || 'ללא טקסט';
            log.push(`${btnId}: ${visible} - ${disabled} - "${text}"`);
        }
    });

    // 5. פילטרים וחיפוש
    log.push('');
    log.push('--- פילטרים וחיפוש ---');
    const searchInput = document.querySelector('input[type="search"], input[placeholder*="חיפוש"], input[placeholder*="search"]');
    if (searchInput) {
        const value = searchInput.value || 'ריק';
        const visible = searchInput.offsetParent !== null ? 'נראה' : 'לא נראה';
        log.push(`חיפוש: "${value}" (${visible})`);
    }

    const filters = document.querySelectorAll('.filter, .form-select, select');
    filters.forEach((filter, index) => {
        const value = filter.value || 'לא נבחר';
        const visible = filter.offsetParent !== null ? 'נראה' : 'לא נראה';
        log.push(`פילטר ${index + 1}: "${value}" (${visible})`);
    });

    // 6. סטטיסטיקות תזרימים
    log.push('');
    log.push('--- סטטיסטיקות תזרימים ---');
    const stats = ['totalInflow', 'totalOutflow', 'netFlow', 'balance'];
    stats.forEach(statId => {
        const element = document.getElementById(statId);
        if (element) {
            const value = element.textContent.trim();
            const visible = element.offsetParent !== null ? 'נראה' : 'לא נראה';
            log.push(`${statId}: ${value} (${visible})`);
        }
    });

    // 7. מידע טכני
    log.push('');
    log.push('--- מידע טכני ---');
    log.push(`זמן יצירת הלוג: ${timestamp}`);
    log.push(`גרסת דפדפן: ${navigator.userAgent}`);
    log.push(`רזולוציה מסך: ${screen.width}x${screen.height}`);
    log.push(`גודל חלון: ${window.innerWidth}x${window.innerHeight}`);

    if (performance.timing) {
        const loadTime = performance.timing.loadEventEnd - performance.timing.navigationStart;
        log.push(`זמן טעינת עמוד: ${loadTime}ms`);
    }

    if (navigator.deviceMemory) {
        log.push(`זיכרון זמין: ${navigator.deviceMemory}GB`);
    }

    log.push(`שפת דפדפן: ${navigator.language}`);
    log.push(`פלטפורמה: ${navigator.platform}`);

    // 8. מצב נתונים מפורט
    log.push('');
    log.push('--- מצב נתונים מפורט ---');
    if (window.cashFlowsData && window.cashFlowsData.length > 0) {
        log.push(`מספר תזרימי מזומנים: ${window.cashFlowsData.length}`);

        // ניתוח לפי סוג
        const incomeFlows = window.cashFlowsData.filter(cf => cf.type === 'income');
        const expenseFlows = window.cashFlowsData.filter(cf => cf.type === 'expense');
        const transferFlows = window.cashFlowsData.filter(cf => cf.type === 'transfer');

        log.push(`הכנסות: ${incomeFlows.length} תזרימים`);
        log.push(`הוצאות: ${expenseFlows.length} תזרימים`);
        log.push(`העברות: ${transferFlows.length} תזרימים`);

        // חישוב סכומים מפורט
        const totalIncome = incomeFlows.reduce((sum, cf) => sum + (cf.amount || 0), 0);
        const totalExpense = expenseFlows.reduce((sum, cf) => sum + (cf.amount || 0), 0);
        const totalTransfer = transferFlows.reduce((sum, cf) => sum + (cf.amount || 0), 0);

        log.push(`סה"כ הכנסות: ${totalIncome.toLocaleString()}`);
        log.push(`סה"כ הוצאות: ${totalExpense.toLocaleString()}`);
        log.push(`סה"כ העברות: ${totalTransfer.toLocaleString()}`);
        log.push(`יתרה כוללת: ${(totalIncome - totalExpense).toLocaleString()}`);

        // תזרים אחרון
        const lastFlow = window.cashFlowsData[0];
        if (lastFlow) {
            log.push(`תזרים אחרון: ${lastFlow.date} - ${lastFlow.type} - ${lastFlow.amount}`);
        }
    } else {
        log.push('❌ אין נתוני תזרימי מזומנים');
    }

    // 9. מצב מערכות גלובליות
    log.push('');
    log.push('--- מצב מערכות גלובליות ---');
    const globalSystems = [
        'showSuccessNotification',
        'showErrorNotification',
        'restoreSectionStates',
        'UnifiedCacheManager',
        'getPreference',
        'loadEntityColors',
        'applyColorScheme'
    ];

    globalSystems.forEach(systemName => {
        const exists = typeof window[systemName] === 'function' || typeof window[systemName] === 'object';
        log.push(`${systemName}: ${exists ? '✅ זמין' : '❌ לא זמין'}`);
    });

    // 10. מצב העדפות
    log.push('');
    log.push('--- מצב העדפות ---');
    if (window.cashFlowsPreferences) {
        log.push('העדפות נטענו: ✅');
        Object.keys(window.cashFlowsPreferences).forEach(key => {
            const value = window.cashFlowsPreferences[key];
            log.push(`  ${key}: ${typeof value === 'object' ? JSON.stringify(value) : value}`);
        });
    } else {
        log.push('❌ העדפות לא נטענו');
    }

    // 11. מצב צבעים דינמיים
    log.push('');
    log.push('--- מצב צבעים דינמיים ---');
    const colorVars = [
        '--cash-flow-color',
        '--cash-flow-bg-color',
        '--account-color',
        '--income-color',
        '--expense-color'
    ];

    colorVars.forEach(colorVar => {
        const value = getComputedStyle(document.documentElement).getPropertyValue(colorVar);
        log.push(`${colorVar}: ${value || 'לא מוגדר'}`);
    });

    // 12. שגיאות והערות מהקונסולה
