deleteConditionViaCrud(conditionId, entityId, entityType = 'plan') {
  const crudManager = window.conditionsCRUDManager;
  if (!crudManager) {
    window.showNotification?.('מערכת ניהול התנאים אינה זמינה כרגע.', 'error');
    return;
  }

  try {
    crudManager.setContext?.({ entityType });
    const success = await crudManager.deleteCondition(Number(conditionId), Number(entityId));
    if (success) {
      window.showNotification?.('התנאי נמחק בהצלחה', 'success');
      window.dispatchEvent(new CustomEvent('tradePlanConditionsUpdated', {
        detail: {
          action: 'delete',
          entityType,
          tradePlanId: entityType === 'plan' ? Number(entityId) : null,
          tradeId: entityType === 'trade' ? Number(entityId) : null,
          payload: { conditionId: Number(conditionId) }
        }
      }));
      const modalElement = getTradePlansModalElement();
      if (modalElement) {
        loadTradePlanConditionsSummary(modalElement, { showLoading: false });
      }
    }
  } catch (error) {
    window.Logger?.error('Failed to delete condition from summary', { error: error?.message, conditionId }, { page: 'trade_plans' });
    window.showNotification?.('שגיאה במחיקת התנאי', 'error');
  }
}

getTradePlanConditionsForEvaluation(entityId) {
  const numericId = Number(entityId);
  const cached = window.ConditionsSummaryRenderer?.getConditions?.('plan', numericId);
  if (Array.isArray(cached) && cached.length) {
    return cached;
  }

  // Use ConditionsCRUDManager if available
  if (window.conditionsCRUDManager) {
    try {
      window.conditionsCRUDManager.setContext({ entityType: 'plan' });
      const data = await window.conditionsCRUDManager.readConditions(entityId, false);
      if (Array.isArray(data)) {
        window.ConditionsSummaryRenderer?.setConditions?.('plan', numericId, data);
      }
      return data || [];
    } catch (error) {
      window.Logger?.error('Failed to load conditions via ConditionsCRUDManager', { error: error?.message, entityId }, { page: 'trade_plans' });
      throw new Error('טעינת התנאים נכשלה');
    }
  }

  // Fallback to direct API call if ConditionsCRUDManager not available
  const response = await fetch(`/api/plan-conditions/trade-plans/${entityId}/conditions`);
  if (!response.ok) {
    throw new Error('טעינת התנאים נכשלה');
  }
  const payload = await response.json();
  const data = Array.isArray(payload?.data) ? payload.data : (Array.isArray(payload) ? payload : []);
  if (Array.isArray(data)) {
    window.ConditionsSummaryRenderer?.setConditions?.('plan', numericId, data);
  }
  return data;
}

