          window.showConfirmationDialog(
            'מחיקת הערה',
            'האם אתה בטוח שברצונך למחוק את ההערה?',
            () => resolve(true),
            () => resolve(false),
            'danger'
          );
        });
      } else {
        if (window.showDeleteWarning) {
          confirmed = await new Promise((resolve) => {
            window.showDeleteWarning(
              'האם אתה בטוח שברצונך למחוק את ההערה?',
              () => resolve(true),
