legacyFetchTradingAccounts() {
  const response = await fetch(`/api/trading-accounts/?_t=${Date.now()}`, {
    method: 'GET',
    headers: {
      'Content-Type': 'application/json',
      'Cache-Control': 'no-cache'
    }
  });

  if (!response.ok) {
    if (response.status === 401 || response.status === 403) {
      window.Logger?.warn?.('⚠️ Trading accounts API unauthorized, returning empty list', { status: response.status }, { page: 'trading_accounts' });
      return [];
    }
    throw new Error(`HTTP error! status: ${response.status}`);
  }

  const result = await response.json();
  return result.data || result || [];
}

getCurrencySymbol(currencyValue) {
  if (!currencyValue) {
    return '$';
  }

  const valueUpper = typeof currencyValue === 'string' ? currencyValue.toUpperCase() : currencyValue;

  switch (valueUpper) {
    case '$':
    case '₪':
    case '€':
    case '£':
    case '¥':
      return currencyValue;
    case 'USD':
      return '$';
    case 'ILS':
      return '₪';
    case 'EUR':
      return '€';
    case 'GBP':
      return '£';
    case 'JPY':
      return '¥';
    default:
      return currencyValue;
  }
}

