            }
          })()}
        </td>
      </tr>
    `;
    } catch (error) {
      window.Logger.error(`❌ Error processing design ${index + 1}:`, error, { page: "trade_plans" });
      return `<tr><td colspan="11" class="text-center text-danger">שגיאה בעיבוד תכנון ${index + 1}</td></tr>`;
    }
  }).join('');
