updateTradingAccount(tradingAccountId, tradingAccountData) {
  try {
    window.Logger.info('📝 מעדכן חשבון מסחר:', tradingAccountId, tradingAccountData, { page: "trading_accounts" });

    // ולידציה בסיסית
    if (!tradingAccountId || !tradingAccountData) {
