formatDateShort(value) {
    const resolved = resolveDateValue(value);
    if (!resolved) {
        return '';
    }
    if (window.FieldRendererService?.renderDateShort) {
        try {
            return window.FieldRendererService.renderDateShort(resolved) || '';
        } catch (error) {
            window.Logger?.warn?.('⚠️ renderDateShort failed', { error: error?.message }, { page: 'index' });
        }
    }
    try {
        const dateObj = new Date(resolved);
        if (Number.isNaN(dateObj.getTime())) {
            return '';
        }
        return window.formatDate ? window.formatDate(dateObj) : (window.dateUtils?.formatDate ? window.dateUtils.formatDate(dateObj) : dateObj.toLocaleDateString('he-IL', { day: '2-digit', month: '2-digit', year: '2-digit' }));
    } catch (error) {
        window.Logger?.warn?.('⚠️ formatDateShort fallback failed', { error: error?.message }, { page: 'index' });
        return '';
    }
}

formatDailyChange(dailyChange) {
  try {
  if (dailyChange === undefined || dailyChange === null) {
    return '-';
  }

  const changeValue = parseFloat(dailyChange);
  const isPositive = changeValue >= 0;
  const sign = isPositive ? '+' : '';
  const formattedValue = `${sign}${Math.abs(changeValue).toFixed(2)}%`;

  // קבלת צבעים מהעדפות או ברירת מחדל
  const colors = window.getTableColors ? window.getTableColors() : { 
    positive: '#28a745', 
    negative: '#dc3545' 
  };

  const color = isPositive ? colors.positive : colors.negative;

  const colorClass = isPositive ? 'numeric-value-positive' : 'numeric-value-negative';
  return `<span class="${colorClass}">${formattedValue}</span>`;
  } catch (error) {
    window.Logger.error('Error in formatDailyChange:', error, { dailyChange, page: "trades" });
    return '-';
  }
}

parseDateToTimestamp = (value) => {
        if (!value && value !== 0) {
            return null;
        }
        if (typeof value === 'number' && Number.isFinite(value)) {
            return value;
        }
        if (value instanceof Date) {
            return value.getTime();
        }
        if (typeof value === 'string') {
            const trimmed = value.trim();
            if (!trimmed) {
                return null;
            }

            const dateMatch = trimmed.match(/^(\d{4}-\d{2}-\d{2})/);
            if (dateMatch) {
                const datePart = dateMatch[1];
                const timestamp = Date.parse(`${datePart}T00:00:00Z`);
                if (!Number.isNaN(timestamp)) {
                    return timestamp;
                }
            }

            const parsed = Date.parse(trimmed);
            if (!Number.isNaN(parsed)) {
                const normalized = new Date(parsed);
                normalized.setHours(0, 0, 0, 0);
                return normalized.getTime();
            }

            return null;
        }
        return null;
    }

parseAlertCondition(condition) {
  try {
    if (!condition || !condition.includes(' | ')) {
      return { variable: 'price', operator: 'moreThen', value: '' };
    }

    const parts = condition.split(' | ');
    return {
      variable: parts[0] || 'price',
      operator: parts[1] || 'moreThen',
      value: parts[2] || '',
    };
  } catch (error) {
    window.Logger.error('שגיאה בפירוק תנאי התראה:', error, { page: "alerts" });
    if (typeof window.showErrorNotification === 'function') {
      window.showErrorNotification('שגיאה בפירוק תנאי התראה', error.message);
    }
    return { variable: 'price', operator: 'moreThen', value: '' };
  }
}

parseFieldValue(input) {
  if (!input) {
    return 0;
  }
  const raw = (input.value || '').toString().trim().replace(/,/g, '');
  if (raw === '' || raw === '.' || raw === '-' || raw === '-.') {
    return 0;
  }
  const parsed = Number(raw);
  return Number.isFinite(parsed) ? parsed : 0;
}

parsePriceValue(priceInput, priceDisplay) {
  const priceFromInput = parseFieldValue(priceInput);
  if (priceFromInput > 0) {
    return priceFromInput;
  }

  if (priceDisplay && priceDisplay.textContent) {
    const normalized = priceDisplay.textContent.replace(/[^\d.\-]/g, '');
    const parsed = Number(normalized);
    if (Number.isFinite(parsed) && parsed > 0) {
      return parsed;
    }
  }

  return 0;
}

formatAmount(amount) {
  try {
    const numericAmount = Number(amount);
    if (!Number.isFinite(numericAmount)) {
      return '<span class="text-muted">לא זמין</span>';
    }

    // שימוש ישיר ב-FieldRendererService - המערכת תמיד זמינה דרך BASE package
    if (window.FieldRendererService?.renderAmount) {
      return window.FieldRendererService.renderAmount(numericAmount, '$', 2, false);
    }

    // Fallback ל-Translation Utilities
    if (window.formatCurrencyWithCommas && typeof window.formatCurrencyWithCommas === 'function') {
      return window.formatCurrencyWithCommas(numericAmount, 'USD');
    }

    // Fallback למקרה נדיר ביותר שהמערכת לא זמינה
    return new Intl.NumberFormat('he-IL', {
      style: 'currency',
      currency: 'USD',
    }).format(numericAmount);
  } catch (error) {
    window.Logger?.error('שגיאה בעיצוב סכום:', error, { page: "cash_flows" });
    if (typeof window.showErrorNotification === 'function') {
      window.showErrorNotification('שגיאה בעיצוב סכום', error.message);
    }
    return amount?.toString() || '-';
  }
}

formatCashFlowAmount(amount, type = null, currencySymbol = '$') {
  if (!amount && amount !== 0) {return '-';}

  const numAmount = Number(amount);
  if (Number.isNaN(numAmount)) {return '-';}

  const typeLower = type ? String(type).toLowerCase() : '';
  const positiveTypes = new Set(['deposit', 'dividend', 'transfer_in', 'other_positive', 'currency_exchange_to']);
  const negativeTypes = new Set(['withdrawal', 'fee', 'transfer_out', 'other_negative', 'currency_exchange_from']);

  let effectiveAmount = numAmount;
  if (typeLower) {
    if (positiveTypes.has(typeLower)) {
      effectiveAmount = Math.abs(numAmount);
    } else if (negativeTypes.has(typeLower)) {
      effectiveAmount = -Math.abs(numAmount);
    }
  }

  // שימוש ישיר ב-FieldRendererService - המערכת תמיד זמינה דרך BASE package
  const baseAmount = window.FieldRendererService?.renderAmount
    ? window.FieldRendererService.renderAmount(effectiveAmount, currencySymbol || '$', 2, true)
    : '<span class="numeric-value-zero">-</span>';

  if (window.getTableColors && typeof window.getTableColors === 'function') {
    const colors = window.getTableColors();
    const color = effectiveAmount >= 0 ? colors.positive : colors.negative;
    return baseAmount.replace('<span', `<span style="color: ${color};"`);
  }

  return baseAmount;
}

formatText(command, mode = 'add') {
  try {
    const editorId = mode === 'edit' ? 'editNoteContent' : 'noteContent';
    const editor = document.getElementById(editorId);

  if (!editor) {
    return;
  }

  editor.focus();

  switch (command) {
  case 'bold':
    document.execCommand('bold', false, null);
    break;
  case 'italic':
    document.execCommand('italic', false, null);
    break;
  case 'underline':
    document.execCommand('underline', false, null);
    break;
  case 'strikethrough':
    document.execCommand('strikeThrough', false, null);
    break;
  case 'h1':
    document.execCommand('formatBlock', false, '<h1>');
    break;
  case 'h2':
    document.execCommand('formatBlock', false, '<h2>');
    break;
  case 'h3':
    document.execCommand('formatBlock', false, '<h3>');
    break;
  case 'ul':
    document.execCommand('insertUnorderedList', false, null);
    break;
  case 'ol':
    document.execCommand('insertOrderedList', false, null);
    break;
  case 'link': {
    // Function to handle link insertion
    const insertLink = (url) => {
      if (url && url.trim()) {
        document.execCommand('createLink', false, url);
        if (typeof window.showSuccessNotification === 'function') {
          window.showSuccessNotification('עורך טקסט', 'לינק נוסף בהצלחה');
        }
      }
    };

    // Use a custom prompt or fallback to browser prompt
    if (typeof window.showCustomPrompt === 'function') {
      window.showCustomPrompt(
        'הוספת לינק',
        'הכנס כתובת URL:',
        'http://',
        insertLink,
        () => window.Logger.info('❌ הוספת לינק - משתמש ביטל', { page: "notes" })
      );
    } else {
      // Fallback to browser prompt
      const url = prompt('הכנס כתובת URL:', 'http://');
      insertLink(url);
    }
    break;
  }
  default:
    // window.Logger.warn(`⚠️ פקודה לא מוכרת: ${command}`, { page: "notes" });
  }

  } catch (error) {
    window.Logger.error('שגיאה בעיצוב טקסט:', error, { page: "notes" });
    if (typeof window.showErrorNotification === 'function') {
      window.showErrorNotification('שגיאה בעיצוב טקסט', error.message);
    }
  }
}

clearFormatting(mode = 'add') {
  try {
    const editorId = mode === 'edit' ? 'editNoteContent' : 'noteContent';
    const editor = document.getElementById(editorId);

  if (!editor) {
    return;
  }

  editor.focus();
  document.execCommand('removeFormat', false, null);

  } catch (error) {
    window.Logger.error('שגיאה בניקוי עיצוב:', error, { page: "notes" });
    if (typeof window.showErrorNotification === 'function') {
      window.showErrorNotification('שגיאה בניקוי עיצוב', error.message);
    }
  }
}

parseValidDate = (value) => {
      if (!value) {
        return null;
      }
      if (value instanceof Date) {
        return Number.isNaN(value.getTime()) ? null : value;
      }
      // Use dateUtils for consistent date parsing
      if (typeof value === 'object') {
        const nestedCandidate = value.local || value.utc || value.iso || value.timestamp;
        return parseValidDate(nestedCandidate);
      }
      const candidate = new Date(value);
      return Number.isNaN(candidate.getTime()) ? null : candidate;
    }

formatCellValue(value, column) {
  try {
    if (value === null || value === undefined) {
      return '';
    }

    // Apply formatting based on column type
    switch (column.type) {
    case 'date':
      return window.formatDate ? window.formatDate(value) : value;
    case 'number':
      return formatNumber(value);
    case 'currency':
      return formatCurrency(value);
    case 'status':
      return formatStatus(value);
    default:
      return String(value);
    }
  } catch (error) {
    window.Logger.error('שגיאה בעיצוב ערך תא:', error, { page: "database" });
    if (typeof window.showErrorNotification === 'function') {
      window.showErrorNotification('שגיאה בעיצוב ערך תא', error.message);
    }
    return String(value || '');
  }
}

formatNumber(number) {
  try {
    if (number === null || number === undefined) {return '';}
    return Number(number).toLocaleString('he-IL');
  } catch (error) {
    window.Logger.error('שגיאה בעיצוב מספר:', error, { page: "database" });
    if (typeof window.showErrorNotification === 'function') {
      window.showErrorNotification('שגיאה בעיצוב מספר', error.message);
    }
    return String(number || '');
  }
}

formatCurrency(amount) {
  try {
    if (amount === null || amount === undefined) {return '';}
    return new Intl.NumberFormat('he-IL', {
      style: 'currency',
      currency: 'USD',
    }).format(amount);
  } catch (error) {
    window.Logger.error('שגיאה בעיצוב מטבע:', error, { page: "database" });
    if (typeof window.showErrorNotification === 'function') {
      window.showErrorNotification('שגיאה בעיצוב מטבע', error.message);
    }
    return String(amount || '');
  }
}

formatStatus(status) {
  try {
    if (!status) {return '';}

    const statusMap = {
      'active': 'פעיל',
      'inactive': 'לא פעיל',
      'pending': 'ממתין',
      'completed': 'הושלם',
      'cancelled': 'בוטל',
    };

    return statusMap[status] || status;
  } catch (error) {
    window.Logger.error('שגיאה בעיצוב סטטוס:', error, { page: "database" });
    if (typeof window.showErrorNotification === 'function') {
      window.showErrorNotification('שגיאה בעיצוב סטטוס', error.message);
    }
    return String(status || '');
  }
}
